import React from "react";
import { Link } from "react-router-dom";

const products = [
  {
    id: 1,
    title: "MacBook Air",
    price: 45000,
    description: "Good condition laptop for coding and study",
    image:
      "https://images.unsplash.com/photo-1517336714739-489689fd1ca8?w=500",
  },
  {
    id: 2,
    title: "Engineering Books",
    price: 1200,
    description: "Complete first year books set",
    image:
      "https://images.unsplash.com/photo-1516979187457-637abb4f9353?w=500",
  },
  {
    id: 3,
    title: "Study Table",
    price: 2500,
    description: "Wooden table for hostel/study room",
    image:
      "https://images.unsplash.com/photo-1505693416388-ac5ce068fe85?w=500",
  },
];

function Home() {
  return (
    <div
      style={{
        backgroundColor: "#f3f4f6",
        minHeight: "100vh",
        fontFamily: "Arial",
      }}
    >
      {/* Navbar */}
      <nav
        style={{
          backgroundColor: "#2563eb",
          padding: "15px 40px",
          display: "flex",
          justifyContent: "space-between",
          alignItems: "center",
          color: "white",
        }}
      >
        <h2 style={{ margin: 0 }}>CampusKart</h2>

        <input
          type="text"
          placeholder="Search products..."
          style={{
            padding: "10px",
            width: "300px",
            borderRadius: "6px",
            border: "none",
            outline: "none",
          }}
        />
      </nav>

      {/* Hero */}
      <div
        style={{
          textAlign: "center",
          padding: "50px 20px",
        }}
      >
        <h1
          style={{
            fontSize: "42px",
            marginBottom: "10px",
            color: "#111827",
          }}
        >
          Student Marketplace
        </h1>

        <p
          style={{
            fontSize: "18px",
            color: "#6b7280",
          }}
        >
          Buy and Sell Products Easily Inside Campus
        </p>
      </div>

      {/* Product Cards */}
      <div
        style={{
          display: "flex",
          flexWrap: "wrap",
          justifyContent: "center",
          gap: "30px",
          padding: "20px",
        }}
      >
        {products.map((product) => (
          <Link
            key={product.id}
            to={`/product/${product.id}`}
            style={{
              textDecoration: "none",
            }}
          >
            <div
              style={{
                backgroundColor: "white",
                width: "300px",
                borderRadius: "12px",
                overflow: "hidden",
                boxShadow: "0 4px 15px rgba(0,0,0,0.1)",
              }}
            >
              <img
                src={product.image}
                alt={product.title}
                style={{
                  width: "100%",
                  height: "220px",
                  objectFit: "cover",
                }}
              />

              <div style={{ padding: "20px" }}>
                <h2
                  style={{
                    color: "#111827",
                  }}
                >
                  {product.title}
                </h2>

                <p
                  style={{
                    color: "#6b7280",
                  }}
                >
                  {product.description}
                </p>

                <h3
                  style={{
                    color: "#16a34a",
                  }}
                >
                  ₹{product.price}
                </h3>

                <button
                  style={{
                    width: "100%",
                    backgroundColor: "#2563eb",
                    color: "white",
                    padding: "12px",
                    border: "none",
                    borderRadius: "8px",
                    cursor: "pointer",
                    fontSize: "16px",
                  }}
                >
                  View Details
                </button>
              </div>
            </div>
          </Link>
        ))}
      </div>
    </div>
  );
}

export default Home;
